DROP TABLE IF EXISTS `excel_column_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `excel_column_config` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `table_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '对应的业务表名',
  `field_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Java字段名',
  `column_name_zh_cn` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Excel列头（中文）',
  `column_name_en_us` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Excel列头（英文）',
  `sort` int NOT NULL COMMENT '列顺序',
  `enabled` tinyint DEFAULT '1' COMMENT '是否启用（1=是0=否）',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_table_field` (`table_name`,`field_name`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Excel动态列头配置表';
