  `range_rule` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '值范围',
  `key_map` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '键的映射',
  `value_map` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '值的映射',
  `dict_type_affiliation` bigint DEFAULT NULL COMMENT '对于属性来说，车型id',
  `rule_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '校验类型',
  `original_system` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '原系统',
  `uuid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '分组唯一标识',
  PRIMARY KEY (`dict_code`),
  KEY `sys_dict_data_uuid_IDX` (`uuid`) USING BTREE,
  KEY `sys_dict_data_dict_type_IDX` (`dict_type`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1622 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='字典数据表';
