CREATE TABLE `sys_i18n` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键UUID',
  `lang_key` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '翻译键（如user.title）',
