  `lang_value` varchar(1000) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '翻译内容',
  `module` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '所属模块 user/role/menu/common',
