--
-- Table structure for table `xml_file`
--

DROP TABLE IF EXISTS `xml_file`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `xml_file` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `file_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件名',
  `file_path` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小',
  `file_level` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '文件分级',
  `version` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '版本号',
  `is_latest` tinyint(1) DEFAULT '1' COMMENT '是否最新版本',
  `pdf_path` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'CoC PDF路径',
  `status` tinyint DEFAULT '0' COMMENT '状态(0正常 1停用)',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标志(0存在 2删除)',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `xml_template_id` bigint DEFAULT NULL,
  `vin` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'VIN',
  `model_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '车型代码',
