DROP TABLE IF EXISTS `xml_template`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `xml_template` (
  `template_id` bigint NOT NULL AUTO_INCREMENT COMMENT '模板ID',
  `template_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模板编码',
  `template_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模板名称',
  `model_dict_code` bigint NOT NULL COMMENT '车型字典ID（对应sys_dict_data.dict_code）',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态（0正常 1停用）',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  `country` varchar(300) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '国家，英文逗号分隔',
  `energy_type` bigint DEFAULT NULL COMMENT '能源类型，字典id',
  `version` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '1.0' COMMENT '版本号',
  `uuid` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_last` tinyint DEFAULT '1',
  PRIMARY KEY (`template_id`),
  UNIQUE KEY `xml_template_unique` (`template_code`,`version`,`deleted`),
  KEY `idx_model_dict_code` (`model_dict_code`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='xml模板表';
/*!40101 SET character_set_client = @saved_cs_client */;

