  `change_desc` text COLLATE utf8mb4_unicode_ci COMMENT '变更描述',
  `diff_content` longtext COLLATE utf8mb4_unicode_ci COMMENT '差异内容',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_file_id` (`file_id`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='XML版本历史表';
